scrollAnimations.keyframes:
@keyframes fadeInUp { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }
@keyframes slideInLeft { from { opacity: 0; transform: translateX(-40px); } to { opacity: 1; transform: translateX(0); } }
@keyframes slideInRight { from { opacity: 0; transform: translateX(40px); } to { opacity: 1; transform: translateX(0); } }
@keyframes scaleReveal { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }

scrollAnimations.usage:
.animate-on-scroll { animation: fadeInUp 0.8s ease both; animation-timeline: view(); animation-range: entry 10% cover 40%; }
.slide-left { animation: slideInLeft 0.8s ease both; animation-timeline: view(); animation-range: entry 10% cover 40%; }
.slide-right { animation: slideInRight 0.8s ease both; animation-timeline: view(); animation-range: entry 10% cover 40%; }
.scale-reveal { animation: scaleReveal 0.6s ease both; animation-timeline: view(); animation-range: entry 10% cover 35%; }
